<style>
	/* Unquoted url() — opaque content preserved verbatim (the `://` colon is not a property
	colon); lowercase url() also has its inner whitespace trimmed. */
	@namespace url(http://www.w3.org/1999/xhtml);
	@namespace svg url(http://www.w3.org/2000/svg);

	/* Uppercase URL() is NOT a url-token (lowercase only), so its inner whitespace is
	preserved verbatim rather than trimmed. */
	@namespace ns URL(  http://www.w3.org/2000/svg  );
</style>
